import React, { useEffect, useState } from "react";
import { Users, Search, Apple } from "lucide-react";
import { supabase } from "./lib/supabase";

export function MembersPage({ onSelectMember }: { onSelectMember: (user: any) => void }) {
  const [members, setMembers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchMembers = async () => {
      const { data, error } = await supabase
        .from('profiles') // <--- Verifica que el nombre coincide con tu tabla en Supabase
        .select('*');

      if (error) {
        console.error("Error de Supabase:", error.message);
      } else {
        setMembers(data || []);
      }
      setLoading(false);
    };
    fetchMembers();
  }, []);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Members</h1>
          <p className="text-gray-400 mt-1">Gestiona los atletas de tu gimnasio</p>
        </div>
      </div>

      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-[#121212] border-b border-[#2a2a2a] text-gray-400 text-xs uppercase">
            <tr>
              <th className="p-4">Nombre</th>
              <th className="p-4">ID de Usuario</th>
              <th className="p-4 text-right">Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-[#2a2a2a]">
            {loading ? (
              <tr><td colSpan={3} className="p-10 text-center text-neon">Cargando atletas...</td></tr>
            ) : members.map((member) => (
              <tr key={member.id} className="hover:bg-white/5 transition-colors">
                <td className="p-4 flex items-center gap-3">
                  <div className="w-8 h-8 bg-[#39FF14]/20 rounded-full flex items-center justify-center text-[#39FF14] font-bold">
                    {member.first_name[0]}
                  </div>
                  <span className="font-medium text-white">{member.first_name} {member.last_name}</span>
                </td>
                <td className="p-4 text-xs text-gray-500 font-mono">{member.id}</td>
                <td className="p-4 text-right">
                  <button 
                    onClick={() => onSelectMember(member)}
                    className="bg-[#121212] border border-[#2a2a2a] text-[#39FF14] px-4 py-2 rounded-lg text-sm font-bold hover:bg-[#39FF14] hover:text-black transition-all flex items-center gap-2 ml-auto"
                  >
                    <Apple size={14} /> Planificar Dieta
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
